import React, {useState} from 'react'
import styled from 'styled-components'


const Hr = styled.div `
width:0;
height:1px;
background-color:#1C1C1C;
transition:all 0.3s ease-in;
`

const Messages = styled.div `
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;
	color:#1C1C1C;
}
`

const MyItems = styled.div `
margin-top:20px;
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;

`

const MyProfile = styled.div `
margin-top:20px;
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;

`

const Settings = styled.div `
margin-top:20px;
&:hover {
	cursor:pointer;
}
&:hover ${Hr} {
	width:100%;

`

const LeftBodyPart = styled.div `
font-size:0.9rem;
width:20%;
display:flex;
justify-content:center;
align-items:flex-start;
flex-direction:column;
color:grey;
`


export default function MeSidebar () {
	const [messageActive, setMessageActive] = useState(true)
	const [myItemsActive, setMyItemsActive] = useState(false)
	const [myProfileActive, setMyProfileActive] = useState(false)
	const [settingsActive, setSettingsActive] = useState(false)

	const onMessageClick = () => {
		setMessageActive(true)
	}

	const onMyItemsClick = () => {
		setMyItemsActive(true)
	}

	const onMyProfileClick = () => {
		setMyProfileActive(true)
	}

	const onSettingsClick = () => {
		setSettingsActive(true)
	}

	return (
		<LeftBodyPart>
			<Messages messageActive={messageActive} onClick={onMessageClick}>Messages<Hr /></Messages>
			<MyItems myItemsActive={myItemsActive} onClick={onMyItemsClick}>My Items<Hr /></MyItems>
			<MyProfile myProfileActive={myProfileActive} onClick={onMyProfileClick}>My Profile<Hr /></MyProfile>
			<Settings settingsActive={settingsActive} onClick={onSettingsClick}>Settings<Hr /></Settings>
		</LeftBodyPart>
	)
}
